from pathlib import Path
base=Path('/app')
meta=json.load(open(base/'meta_public.json'))
for name in ['train_X.csv','train_y.csv','test_X.csv']:
    with open(base/name, newline='') as f:
        rows=list(csv.reader(f))
    header=rows[0]
    data=rows[1:]
    print(name, {'header': header, 'data_rows': len(data), 'data_cols': len(data[0]) if data else 0})
print('meta', meta)
print('implied', {
    'N': len(list(csv.reader(open(base/'train_X.csv'))))-1,
    'D': len(next(csv.reader(open(base/'train_X.csv')))),
    'N_new': len(list(csv.reader(open(base/'test_X.csv'))))-1,
    'P': meta['P'],
    'H_shape': (len(list(csv.reader(open(base/'train_X.csv'))))-1, meta['P']),
    'H_new_shape': (len(list(csv.reader(open(base/'test_X.csv'))))-1, meta['P'])
})"
